@startuml
skinparam noteFontColor black
skinparam classBackgroundColor #FFFFE0
skinparam classBorderColor gray

class "ex:MyShapemaxCount" {
  age : integer : maxCount[0..1]
}

note right of ex:MyShapemaxCount 
<font color=black>
<pre>@prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>.
@prefix schema: <http://schema.org/>.
@prefix sh: <http://www.w3.org/ns/shacl#>.
@prefix xsd: <http://www.w3.org/2001/XMLSchema#>.
@prefix ex: <http://example.org/ns#>.

ex:MyShapemaxCount a sh:NodeShape ;
sh:targetClass ex:Person ;
sh:property [
    sh:path ex:age ;
    sh:maxCount 1 ;
    sh:datatype xsd:integer ;
].</pre></font>
end note

@enduml
